package com.banking.transaction;

import com.banking.model.Account;
import com.banking.model.Transaction;

import java.math.BigDecimal;

public class TransactionValidator {

    private static final BigDecimal MAX_SINGLE_TRANSACTION = new BigDecimal("50000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");
    private static final BigDecimal DAILY_TRANSFER_LIMIT = new BigDecimal("100000.00");
    private static final int MAX_DESCRIPTION_LENGTH = 250;

    public static class ValidationResult {
        private final boolean valid;
        private final String errorMessage;

        public ValidationResult(boolean valid, String errorMessage) {
            this.valid = valid;
            this.errorMessage = errorMessage;
        }

        public boolean isValid() { return valid; }
        public String getErrorMessage() { return errorMessage; }
    }

    public ValidationResult validate(Transaction transaction, Account sourceAccount,
                                      BigDecimal dailyTotal) {
        // Check if account is active
        if (!sourceAccount.isActive()) {
            return new ValidationResult(false, "Source account is not active.");
        }

        // Validate amount range
        if (transaction.getAmount().compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
            return new ValidationResult(false,
                    "Transaction amount must be at least " + MIN_TRANSACTION_AMOUNT.toPlainString());
        }

        if (transaction.getAmount().compareTo(MAX_SINGLE_TRANSACTION) > 0) {
            return new ValidationResult(false,
                    "Transaction amount exceeds the maximum limit of " + MAX_SINGLE_TRANSACTION.toPlainString());
        }

        // Check sufficient balance
        if (transaction.getType() == Transaction.TransactionType.TRANSFER
                || transaction.getType() == Transaction.TransactionType.WITHDRAWAL
                || transaction.getType() == Transaction.TransactionType.PAYMENT) {
            if (sourceAccount.getAvailableBalance().compareTo(transaction.getAmount()) < 0) {
                return new ValidationResult(false, "Insufficient funds.");
            }
        }

        // Check daily limit
        BigDecimal newDailyTotal = dailyTotal.add(transaction.getAmount());
        if (newDailyTotal.compareTo(DAILY_TRANSFER_LIMIT) > 0) {
            return new ValidationResult(false,
                    "Transaction would exceed daily transfer limit of " + DAILY_TRANSFER_LIMIT.toPlainString());
        }

        // Validate self-transfer
        if (transaction.getType() == Transaction.TransactionType.TRANSFER
                && transaction.getSourceAccountId().equals(transaction.getDestinationAccountId())) {
            return new ValidationResult(false, "Cannot transfer to the same account.");
        }

        // Validate description length
        if (transaction.getDescription() != null
                && transaction.getDescription().length() > MAX_DESCRIPTION_LENGTH) {
            return new ValidationResult(false,
                    "Description exceeds maximum length of " + MAX_DESCRIPTION_LENGTH + " characters.");
        }

        // Validate currency match
        if (!transaction.getCurrency().equals(sourceAccount.getCurrency())) {
            return new ValidationResult(false, "Currency mismatch between transaction and account.");
        }

        // Check for amount precision (max 2 decimal places for most currencies)
        if (transaction.getAmount().scale() > 2) {
            return new ValidationResult(false, "Amount cannot have more than 2 decimal places.");
        }

        return new ValidationResult(true, "Validation passed.");
    }

    public static String sanitizeInput(String input) {
        if (input == null) return "";
        // Remove potentially dangerous characters
        return input.replaceAll("[<>\"';&|`$(){}\\[\\]\\\\]", "")
                .trim();
    }

    public static boolean isValidAccountNumber(String accountNumber) {
        if (accountNumber == null) return false;
        return accountNumber.matches("^[0-9]{8,16}$");
    }
}


