package com.banking.transaction;

import android.content.Context;
import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import com.banking.model.Account;
import com.banking.model.Transaction;
import com.banking.secure.SecurityManager;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicBoolean;

public class TransactionProcessor {

    private static final String TAG = "TransactionProcessor";
    private static final int MAX_RETRIES = 3;
    private static final long RETRY_DELAY_MS = 2000;
    private static final long TRANSACTION_TIMEOUT_MS = 30000;

    private final Context context;
    private final SecurityManager securityManager;
    private final TransactionValidator validator;
    private final ExecutorService executorService;
    private final Handler mainHandler;
    private final ConcurrentHashMap<String, Transaction> activeTransactions;
    private final List<Transaction> transactionHistory;
    private final Object balanceLock = new Object();

    // Simulated accounts for demo
    private final ConcurrentHashMap<String, Account> accounts;
    private BigDecimal dailyTransactionTotal = BigDecimal.ZERO;

    public interface TransactionCallback {
        void onTransactionStarted(Transaction transaction);
        void onTransactionProgress(Transaction transaction, String message);
        void onTransactionCompleted(Transaction transaction);
        void onTransactionFailed(Transaction transaction, String error);
    }

    public TransactionProcessor(Context context) throws Exception {
        this.context = context.getApplicationContext();
        this.securityManager = new SecurityManager(context);
        this.validator = new TransactionValidator();
        this.executorService = Executors.newFixedThreadPool(2);
        this.mainHandler = new Handler(Looper.getMainLooper());
        this.activeTransactions = new ConcurrentHashMap<>();
        this.transactionHistory = Collections.synchronizedList(new ArrayList<>());
        this.accounts = new ConcurrentHashMap<>();

        initializeDemoAccounts();
    }

    private void initializeDemoAccounts() {
        accounts.put("ACC001", new Account("ACC001", "12345678", "John Doe",
                Account.AccountType.CHECKING, new BigDecimal("15000.00"), "USD"));
        accounts.put("ACC002", new Account("ACC002", "87654321", "John Doe",
                Account.AccountType.SAVINGS, new BigDecimal("50000.00"), "USD"));
        accounts.put("ACC003", new Account("ACC003", "11223344", "Jane Smith",
                Account.AccountType.CHECKING, new BigDecimal("25000.00"), "USD"));
    }

    public void processTransaction(Transaction transaction, TransactionCallback callback) {
        executorService.submit(() -> {
            try {
                // Step 1: Notify start
                notifyOnMain(() -> callback.onTransactionStarted(transaction));

                // Step 2: Add nonce and integrity hash
                String nonce = securityManager.generateNonce();
                transaction.setNonce(nonce);
                String hash = securityManager.hashTransactionData(transaction.getDataForHashing());
                transaction.setIntegrityHash(hash);

                notifyOnMain(() -> callback.onTransactionProgress(transaction, "Validating transaction..."));

                // Step 3: Validate
                Account sourceAccount = accounts.get(transaction.getSourceAccountId());
                if (sourceAccount == null) {
                    failTransaction(transaction, callback, "Source account not found.");
                    return;
                }

                TransactionValidator.ValidationResult validationResult =
                        validator.validate(transaction, sourceAccount, dailyTransactionTotal);

                if (!validationResult.isValid()) {
                    failTransaction(transaction, callback, validationResult.getErrorMessage());
                    return;
                }

                // Step 4: Check for duplicate/replay
                if (activeTransactions.containsKey(transaction.getTransactionId())) {
                    failTransaction(transaction, callback, "Duplicate transaction detected.");
                    return;
                }

                activeTransactions.put(transaction.getTransactionId(), transaction);
                transaction.setStatus(Transaction.TransactionStatus.PROCESSING);

                notifyOnMain(() -> callback.onTransactionProgress(transaction, "Processing transaction..."));

                // Step 5: Encrypt sensitive data for transmission
                SecurityManager.EncryptedData encryptedAmount =
                        securityManager.encrypt(transaction.getAmount().toPlainString());
                SecurityManager.EncryptedData encryptedSource =
                        securityManager.encrypt(transaction.getSourceAccountId());

                // Step 6: Verify integrity before processing
                String verifyHash = securityManager.hashTransactionData(transaction.getDataForHashing());
                if (!verifyHash.equals(transaction.getIntegrityHash())) {
                    failTransaction(transaction, callback, "Transaction integrity check failed.");
                    return;
                }

                notifyOnMain(() -> callback.onTransactionProgress(transaction, "Securing transaction..."));

                // Step 7: Execute the transaction with retry logic
                boolean success = executeWithRetry(transaction, sourceAccount);

                if (success) {
                    transaction.setStatus(Transaction.TransactionStatus.COMPLETED);
                    transactionHistory.add(transaction);
                    dailyTransactionTotal = dailyTransactionTotal.add(transaction.getAmount());

                    // Store transaction record securely
                    securityManager.storeSecurely(
                            "last_transaction_" + transaction.getTransactionId(),
                            transaction.getTransactionId() + ":" + transaction.getStatus().name()
                    );

                    notifyOnMain(() -> callback.onTransactionCompleted(transaction));

                    Log.i(TAG, "Transaction completed: " + transaction.getTransactionId());
                } else {
                    failTransaction(transaction, callback, "Transaction processing failed after retries.");
                }

            } catch (Exception e) {
                Log.e(TAG, "Transaction error", e);
                failTransaction(transaction, callback, "An unexpected error occurred: " + e.getMessage());
            } finally {
                activeTransactions.remove(transaction.getTransactionId());
            }
        });
    }

    private boolean executeWithRetry(Transaction transaction, Account sourceAccount) {
        while (transaction.getRetryCount() < MAX_RETRIES) {
            try {
                synchronized (balanceLock) {
                    return executeBalanceUpdate(transaction, sourceAccount);
                }
            } catch (Exception e) {
                transaction.incrementRetryCount();
                Log.w(TAG, "Transaction retry " + transaction.getRetryCount() + " for " + transaction.getTransactionId(), e);
                if (transaction.getRetryCount() < MAX_RETRIES) {
                    try {
                        Thread.sleep(RETRY_DELAY_MS * transaction.getRetryCount());
                    } catch (InterruptedException ie) {
                        Thread.currentThread().interrupt();
                        return false;
                    }
                }
            }
        }
        return false;
    }

    private boolean executeBalanceUpdate(Transaction transaction, Account sourceAccount) {
        switch (transaction.getType()) {
            case TRANSFER:
                Account destAccount = accounts.get(transaction.getDestinationAccountId());
                if (destAccount == null) return false;

                BigDecimal sourceNewBalance = sourceAccount.getBalance().subtract(transaction.getAmount());
                BigDecimal destNewBalance = destAccount.getBalance().add(transaction.getAmount());

                if (sourceNewBalance.compareTo(BigDecimal.ZERO) < 0) return false;

                sourceAccount.setBalance(sourceNewBalance);
                sourceAccount.setAvailableBalance(sourceNewBalance);
                destAccount.setBalance(destNewBalance);
                destAccount.setAvailableBalance(destNewBalance);
                return true;

            case WITHDRAWAL:
            case PAYMENT:
                BigDecimal newBalance = sourceAccount.getBalance().subtract(transaction.getAmount());
                if (newBalance.compareTo(BigDecimal.ZERO) < 0) return false;

                sourceAccount.setBalance(newBalance);
                sourceAccount.setAvailableBalance(newBalance);
                return true;

            case DEPOSIT:
                BigDecimal depositBalance = sourceAccount.getBalance().add(transaction.getAmount());
                sourceAccount.setBalance(depositBalance);
                sourceAccount.setAvailableBalance(depositBalance);
                return true;

            default:
                return false;
        }
    }

    private void failTransaction(Transaction transaction, TransactionCallback callback, String error) {
        transaction.setStatus(Transaction.TransactionStatus.FAILED);
        transactionHistory.add(transaction);
        activeTransactions.remove(transaction.getTransactionId());
        Log.e(TAG, "Transaction failed: " + transaction.getTransactionId() + " - " + error);
        notifyOnMain(() -> callback.onTransactionFailed(transaction, error));
    }

    private void notifyOnMain(Runnable action) {
        mainHandler.post(action);
    }

    public Account getAccount(String accountId) {
        return accounts.get(accountId);
    }

    public List<Account> getAllAccounts() {
        return new ArrayList<>(accounts.values());
    }

    public List<Transaction> getTransactionHistory() {
        return new ArrayList<>(transactionHistory);
    }

    public List<Transaction> getTransactionHistoryForAccount(String accountId) {
        List<Transaction> accountTransactions = new ArrayList<>();
        synchronized (transactionHistory) {
            for (Transaction t : transactionHistory) {
                if (accountId.equals(t.getSourceAccountId())
                        || accountId.equals(t.getDestinationAccountId())) {
                    accountTransactions.add(t);
                }
            }
        }
        return accountTransactions;
    }

    public void shutdown() {
        executorService.shutdown();
        try {
            if (!executorService.awaitTermination(5, TimeUnit.SECONDS)) {
                executorService.shutdownNow();
            }
        } catch (InterruptedException e) {
            executorService.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }
}


// ==================== SessionManager.java ====================
package com.banking.secure;

import android.content.Context;
import android.os.Handler;
import android.os.Looper;

public class SessionManager {

    private static final long SESSION_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes
    private static final long WARNING_BEFORE_TIMEOUT_MS = 60 * 1000; // 1 minute warning

    private final Context context;
    private final SecurityManager securityManager;
    private final Handler timeoutHandler;
    private String sessionToken;
    private long lastActivityTimestamp;
    private boolean isAuthenticated;
    private SessionListener listener;

    public interface SessionListener {
        void onSessionTimeout();
        void onSessionTimeoutWarning(long remainingMs);
        void onSessionRefreshed();
    }

    private final Runnable timeoutRunnable = new Runnable() {
        @Override
        public void run() {
            long elapsed = System.currentTimeMillis() - lastActivityTimestamp;
            if (elapsed >= SESSION_TIMEOUT_MS) {
                invalidateSession();
                if (listener != null) {
                    listener.onSessionTimeout();
                }
            } else if (elapsed >= SESSION_TIMEOUT_MS - WARNING_BEFORE_TIMEOUT_MS) {
                if (listener != null) {
                    listener.onSessionTimeoutWarning(SESSION_TIMEOUT_MS - elapsed);
                }
                timeoutHandler.postDelayed(this, 10000); // Check every 10 seconds
            } else {
                timeoutHandler.postDelayed(this, WARNING_BEFORE_TIMEOUT_MS);
            }
        }
    };

    public SessionManager(Context context) throws Exception {
        this.context = context.getApplicationContext();
        this.securityManager = new SecurityManager(context);
        this.timeoutHandler = new Handler(Looper.getMainLooper());
        this.isAuthenticated = false;
    }

    public void setSessionListener(SessionListener listener) {
        this.listener = listener;
    }

    public boolean startSession() {
        try {
            sessionToken = securityManager.generateSessionToken();
            securityManager.storeSecurely("session_token", sessionToken);
            securityManager.storeSecurely("session_start", String.valueOf(System.currentTimeMillis()));
            lastActivityTimestamp = System.currentTimeMillis();
            isAuthenticated = true;
            startTimeoutMonitor();
            return true;
        } catch (Exception e) {
            return false;
        }
    }

    public void refreshActivity() {
        if (isAuthenticated) {
            lastActivityTimestamp = System.currentTimeMillis();
            timeoutHandler.removeCallbacks(timeoutRunnable);
            startTimeoutMonitor();
            if (listener != null) {
                listener.onSessionRefreshed();
            }
        }
    }

    public void invalidateSession() {
        isAuthenticated = false;
        sessionToken = null;
        timeoutHandler.removeCallbacks(timeoutRunnable);
        try {
            securityManager.clearSecureStorage();
        } catch (Exception e) {
            // Log but don't crash
        }
    }

    public boolean isSessionValid() {
        if (!isAuthenticated || sessionToken == null) return false;
        long elapsed = System.currentTimeMillis() - lastActivityTimestamp;
        return elapsed < SESSION_TIMEOUT_MS;
    }

    public String getSessionToken() {
        return sessionToken;
    }

    private void startTimeoutMonitor() {
        timeoutHandler.removeCallbacks(timeoutRunnable);
        timeoutHandler.postDelayed(timeoutRunnable, WARNING_BEFORE_TIMEOUT_MS);
    }
}


// ==================== NetworkSecurityHelper.java ====================
package com.banking.secure;

import android.content.Context;
import android.net.ConnectivityManager;
import android.net.Network;
import android.net.NetworkCapabilities;
import android.net.NetworkInfo;
import android.os.Build;

public class NetworkSecurityHelper {

    public static class NetworkStatus {
        private final boolean connected;
        private final boolean secure;
        private final String networkType;
        private final String warning;

        public NetworkStatus(boolean connected, boolean secure, String networkType, String warning) {
            this.connected = connected;
            this.secure = secure;
            this.networkType = networkType;
            this.warning = warning;
        }

        public boolean isConnected() { return connected; }
        public boolean isSecure() { return secure; }
        public String getNetworkType() { return networkType; }
        public String getWarning() { return warning; }
    }

    public static NetworkStatus checkNetworkSecurity(Context context) {
        ConnectivityManager cm = (ConnectivityManager)
                context.getSystemService(Context.CONNECTIVITY_SERVICE);

        if (cm == null) {
            return new NetworkStatus(false, false, "Unknown", "Cannot check network status.");
        }

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            Network activeNetwork = cm.getActiveNetwork();
            if (activeNetwork == null) {
                return new NetworkStatus(false, false, "None", "No network connection.");
            }

            NetworkCapabilities capabilities = cm.getNetworkCapabilities(activeNetwork);
            if (capabilities == null) {
                return new NetworkStatus(false, false, "Unknown", "Cannot determine network capabilities.");
            }

            boolean isWifi = capabilities.hasTransport(NetworkCapabilities.TRANSPORT_WIFI);
            boolean isCellular = capabilities.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR);
            boolean isVpn = capabilities.hasTransport(NetworkCapabilities.TRANSPORT_VPN);

            String type = isWifi ? "WiFi" : (isCellular ? "Cellular" : "Other");
            if (isVpn) type += " (VPN)";

            // Warn about public WiFi
            if (isWifi && !isVpn) {
                return new NetworkStatus(true, false, type,
                        "You are on a WiFi network. For maximum security, consider using a VPN or mobile data for banking transactions.");
            }

            return new NetworkStatus(true, true, type, null);
        } else {
            NetworkInfo activeNetworkInfo = cm.getActiveNetworkInfo();
            if (activeNetworkInfo == null || !activeNetworkInfo.isConnected()) {
                return new NetworkStatus(false, false, "None", "No network connection.");
            }
            return new NetworkStatus(true, true, activeNetworkInfo.getTypeName(), null);
        }
    }
}


// ==================== AuditLogger.java ====================
package com.banking.secure;

import android.content.Context;
import android.util.Log;

import java.io.BufferedWriter;
import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class AuditLogger {

    private static final String TAG = "AuditLogger";
    private static final String AUDIT_FILE = "banking_audit.log";
    private static final long MAX_LOG_SIZE = 5 * 1024 * 1024; // 5MB

    public enum AuditEvent {
        LOGIN_ATTEMPT,
        LOGIN_SUCCESS,
        LOGIN_FAILURE,
        SESSION_START,
        SESSION_END,
        SESSION_TIMEOUT,
        TRANSACTION_INITIATED,
        TRANSACTION_VALIDATED,
        TRANSACTION_COMPLETED,
        TRANSACTION_FAILED,
        SECURITY_CHECK_PASSED,
        SECURITY_CHECK_FAILED,
        BALANCE_VIEWED,
        SUSPICIOUS_ACTIVITY
    }

    private final Context context;
    private final SecurityManager securityManager;

    public AuditLogger(Context context) throws Exception {
        this.context = context.getApplicationContext();
        this.securityManager = new SecurityManager(context);
    }

    public void logEvent(AuditEvent event, String details) {
        String timestamp = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
                .format(new Date());
        String logEntry = String.format("[%s] %s: %s", timestamp, event.name(), details);

        // Write to encrypted storage
        try {
            securityManager.storeSecurely("audit_" + System.currentTimeMillis(), logEntry);
        } catch (Exception e) {
            Log.e(TAG, "Failed to store audit log securely", e);
        }

        // Write to internal file (not accessible to other apps)
        writeToFile(logEntry);

        // In production, this would also send to a secure remote logging service
        Log.i(TAG, logEntry);
    }

    private void writeToFile(String logEntry) {
        try {
            File logFile = new File(context.getFilesDir(), AUDIT_FILE);

            // Rotate log if too large
            if (logFile.exists() && logFile.length() > MAX_LOG_SIZE) {
                File backupFile = new File(context.getFilesDir(), AUDIT_FILE + ".bak");
                if (backupFile.exists()) backupFile.delete();
                logFile.renameTo(backupFile);
                logFile = new File(context.getFilesDir(), AUDIT_FILE);
            }

            BufferedWriter writer = new BufferedWriter(new FileWriter(logFile, true));
            writer.write(logEntry);
            writer.newLine();
            writer.close();
        } catch (IOException e) {
            Log.e(TAG, "Failed to write audit log", e);
        }
    }
}


